Get-ChildItem -Path src/main/java/com/digitaltravel/erp/controller -Filter *Controller.java -Recurse | ForEach-Object { $content = Get-Content $_.FullName; $content = $content -replace "@PreAuthorize\(`"hasRole\('([^']+)'\)`"\)", "@PreAuthorize(`"hasAnyRole('$1', 'ADMIN')`")"; $content = $content -replace "@PreAuthorize\(`"hasAnyRole\('([^']+)', '([^']+)'\)`"\)", "@PreAuthorize(`"hasAnyRole('$1', '$2', 'ADMIN')`")"; Set-Content $_.FullName -Value $content }
